import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{o as e,c as d,e as r}from"./app-76561525.js";const l={},n=r('<p>HTTP状态码（HTTP Status Code）是用以表示网页服务器HTTP响应状态的3位数字代码。借助状态码，用户可以知道服务器端是正常处理了请求，还是出现了错误。</p><img src="https://img.bookandmusic.cn/blog/2022/01/GmJ6cE.png" alt="GmJ6cE" style="zoom:50%;"><p>它由 RFC 2616 规范定义的，并得到RFC 2518、RFC 2817、RFC 2295、RFC 2774、RFC 4918等规范扩展。</p><p>HTTP 状态码由三个十进制数字组成，第一个十进制数字定义了状态码的类型。</p><p>响应分为五类：信息响应(100–199)，成功响应(200–299)，重定向(300–399)，客户端错误(400–499)和服务器错误 (500–599)：</p><table><thead><tr><th></th><th><strong>类别</strong></th><th><strong>原因短语</strong></th></tr></thead><tbody><tr><td><code>1XX</code></td><td>Informational（信息性状态码）</td><td>信息，服务器收到请求，需要请求者继续执行操作</td></tr><tr><td><code>2XX</code></td><td>Success（成功状态码）</td><td>成功，操作被成功接收并处理</td></tr><tr><td><code>3XX</code></td><td>Redirection（重定向状态码）</td><td>重定向，需要进一步的操作以完成请求</td></tr><tr><td><code>4XX</code></td><td>Client Error（客户端错误状态码）</td><td>客户端错误，请求包含语法错误或无法完成请求</td></tr><tr><td><code>5XX</code></td><td>Server Error（服务器错误状态码）</td><td>服务器错误，服务器在处理请求的过程中发生了错误</td></tr></tbody></table><h2 id="_1xx-临时响应" tabindex="-1"><a class="header-anchor" href="#_1xx-临时响应" aria-hidden="true">#</a> 1xx（临时响应）</h2><blockquote><p>表示临时响应并需要请求者继续执行操作的状态代码。</p></blockquote><table><thead><tr><th style="text-align:center;">状态码</th><th style="text-align:center;">状态码英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td style="text-align:center;">100</td><td style="text-align:center;">Continue</td><td>（继续） 请求者应当继续提出请求。 服务器返回此代码表示已收到请求的第一部分，正在等待其余部分。</td></tr><tr><td style="text-align:center;">101</td><td style="text-align:center;">Switching Protocols</td><td>（切换协议） 请求者已要求服务器切换协议，服务器已确认并准备切换。</td></tr></tbody></table><h2 id="_2xx-成功" tabindex="-1"><a class="header-anchor" href="#_2xx-成功" aria-hidden="true">#</a> 2xx （成功）</h2><blockquote><p>表示成功处理了请求的状态代码。</p></blockquote><table><thead><tr><th style="text-align:center;">状态码</th><th style="text-align:left;">状态码英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td style="text-align:center;">200</td><td style="text-align:left;">OK</td><td>（成功） 服务器已成功处理了请求，该操作是幂等的（Idempotent）。 通常，这表示服务器提供了请求的网页。</td></tr><tr><td style="text-align:center;">201</td><td style="text-align:left;">Created</td><td>（已创建） 请求成功并且服务器创建了新的资源。</td></tr><tr><td style="text-align:center;">202</td><td style="text-align:left;">Accepted</td><td>（已接受） 服务器已接受请求，但尚未处理。即请求已经进入后台排队（异步任务）</td></tr><tr><td style="text-align:center;">203</td><td style="text-align:left;">Non-Authoritative Information</td><td>（非授权信息） 服务器已成功处理了请求，但返回的信息可能来自另一来源。</td></tr><tr><td style="text-align:center;">204</td><td style="text-align:left;">No Content</td><td>（无内容） 服务器成功处理了请求，但没有返回任何内容。</td></tr><tr><td style="text-align:center;">205</td><td style="text-align:left;">Reset Content</td><td>（重置内容） 服务器成功处理了请求，但没有返回任何内容。</td></tr><tr><td style="text-align:center;">206</td><td style="text-align:left;">Partial Content</td><td>（部分内容） 服务器成功处理了部分 GET 请求。</td></tr></tbody></table><h2 id="_3xx-重定向" tabindex="-1"><a class="header-anchor" href="#_3xx-重定向" aria-hidden="true">#</a> 3xx （重定向）</h2><blockquote><p>表示要完成请求，需要进一步操作。 通常，这些状态代码用来重定向。</p></blockquote><table><thead><tr><th style="text-align:center;">状态码</th><th style="text-align:left;">状态码英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td style="text-align:center;">300</td><td style="text-align:left;">Multiple Choices</td><td>（多种选择） 针对请求，服务器可执行多种操作。 服务器可根据请求者 (user agent) 选择一项操作，或提供操作列表供请求者选择。</td></tr><tr><td style="text-align:center;">301</td><td style="text-align:left;">Moved Permanently</td><td>（永久移动） 请求的网页已永久移动到新位置。 服务器返回此响应（对 GET 或 HEAD 请求的响应）时，会自动将请求者转到新位置。</td></tr><tr><td style="text-align:center;">302</td><td style="text-align:left;">Found</td><td>（临时移动） 服务器目前从不同位置的网页响应请求，但请求者应继续使用原有位置来进行以后的请求。</td></tr><tr><td style="text-align:center;">303</td><td style="text-align:left;">See Other</td><td>（查看其他位置） 请求者应当对不同的位置使用单独的 GET 请求来检索响应时，服务器返回此代码。</td></tr><tr><td style="text-align:center;">304</td><td style="text-align:left;">Not Modified</td><td>（未修改） 自从上次请求后，请求的网页未修改过。 服务器返回此响应时，不会返回网页内容。</td></tr><tr><td style="text-align:center;">305</td><td style="text-align:left;">Use Proxy</td><td>（使用代理） 请求者只能使用代理访问请求的网页。 如果服务器返回此响应，还表示请求者应使用代理。</td></tr><tr><td style="text-align:center;">307</td><td style="text-align:left;">Temporary Redirect</td><td>（临时重定向） 服务器目前从不同位置的网页响应请求，但请求者应继续使用原有位置来进行以后的请求。</td></tr></tbody></table><h2 id="_4xx-请求错误" tabindex="-1"><a class="header-anchor" href="#_4xx-请求错误" aria-hidden="true">#</a> 4xx（请求错误）</h2><blockquote><p>这些状态代码表示请求可能出错，妨碍了服务器的处理。</p></blockquote><table><thead><tr><th style="text-align:center;">状态码</th><th style="text-align:center;">状态码英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td style="text-align:center;">400</td><td style="text-align:center;">Bad Request</td><td>（错误请求） 服务器不理解请求的语法。</td></tr><tr><td style="text-align:center;">401</td><td style="text-align:center;">Unauthorized</td><td>（未授权） 请求要求身份验证。 对于需要登录的网页，服务器可能返回此响应。</td></tr><tr><td style="text-align:center;">403</td><td style="text-align:center;">Forbidden</td><td>（禁止） 服务器拒绝请求。</td></tr><tr><td style="text-align:center;">404</td><td style="text-align:center;">Not Found</td><td>（未找到） 服务器找不到请求的网页。</td></tr><tr><td style="text-align:center;">405</td><td style="text-align:center;">Method Not Allowed</td><td>（方法禁用） 禁用请求中指定的方法。</td></tr><tr><td style="text-align:center;">406</td><td style="text-align:center;">Not Acceptable</td><td>（不接受） 无法使用请求的内容特性响应请求的网页。</td></tr><tr><td style="text-align:center;">407</td><td style="text-align:center;">Proxy Authentication Required</td><td>（需要代理授权） 此状态代码与 401（未授权）类似，但指定请求者应当授权使用代理。</td></tr><tr><td style="text-align:center;">408</td><td style="text-align:center;">Request Time-out</td><td>（请求超时） 服务器等候请求时发生超时。</td></tr><tr><td style="text-align:center;">409</td><td style="text-align:center;">Conflict</td><td>（冲突） 服务器在完成请求时发生冲突。 服务器必须在响应中包含有关冲突的信息。</td></tr><tr><td style="text-align:center;">410</td><td style="text-align:center;">Gone</td><td>（已删除） 如果请求的资源已永久删除，服务器就会返回此响应。</td></tr><tr><td style="text-align:center;">411</td><td style="text-align:center;">Length Required</td><td>（需要有效长度） 服务器不接受不含有效内容长度标头字段的请求。</td></tr><tr><td style="text-align:center;">412</td><td style="text-align:center;">Precondition Failed</td><td>（未满足前提条件） 服务器未满足请求者在请求中设置的其中一个前提条件。</td></tr><tr><td style="text-align:center;">413</td><td style="text-align:center;">Request Entity Too Large</td><td>（请求实体过大） 服务器无法处理请求，因为请求实体过大，超出服务器的处理能力。</td></tr><tr><td style="text-align:center;">414</td><td style="text-align:center;">Request-URI Too Large</td><td>（请求的 URI 过长） 请求的 URI（通常为网址）过长，服务器无法处理。</td></tr><tr><td style="text-align:center;">415</td><td style="text-align:center;">Unsupported Media Type</td><td>（不支持的媒体类型） 请求的格式不受请求页面的支持。</td></tr><tr><td style="text-align:center;">416</td><td style="text-align:center;">Requested range not satisfiable</td><td>（请求范围不符合要求） 如果页面无法提供请求的范围，则服务器会返回此状态代码。</td></tr><tr><td style="text-align:center;">417</td><td style="text-align:center;">Expectation Failed</td><td>（未满足期望值） 服务器未满足&quot;期望&quot;请求标头字段的要求。</td></tr></tbody></table><h2 id="_5xx-服务器错误" tabindex="-1"><a class="header-anchor" href="#_5xx-服务器错误" aria-hidden="true">#</a> 5xx（服务器错误）</h2><blockquote><p>这些状态代码表示服务器在尝试处理请求时发生内部错误。 这些错误可能是服务器本身的错误，而不是请求出错。</p></blockquote><table><thead><tr><th style="text-align:center;">状态码</th><th style="text-align:center;">状态码英文名称</th><th>中文描述</th></tr></thead><tbody><tr><td style="text-align:center;">500</td><td style="text-align:center;">Internal Server Error</td><td>（服务器内部错误） 服务器遇到错误，无法完成请求。</td></tr><tr><td style="text-align:center;">501</td><td style="text-align:center;">Not Implemented</td><td>（尚未实施） 服务器不具备完成请求的功能。 例如，服务器无法识别请求方法时可能会返回此代码。</td></tr><tr><td style="text-align:center;">502</td><td style="text-align:center;">Bad Gateway</td><td>（错误网关） 服务器作为网关或代理，从上游服务器收到无效响应。</td></tr><tr><td style="text-align:center;">503</td><td style="text-align:center;">Service Unavailable</td><td>（服务不可用） 服务器目前无法使用（由于超载或停机维护）。 通常，这只是暂时状态。</td></tr><tr><td style="text-align:center;">504</td><td style="text-align:center;">Gateway Time-out</td><td>（网关超时） 服务器作为网关或代理，但是没有及时从上游服务器收到请求。</td></tr><tr><td style="text-align:center;">505</td><td style="text-align:center;">HTTP Version not supported</td><td>（HTTP 版本不受支持） 服务器不支持请求中所用的 HTTP 协议版本。</td></tr></tbody></table>',21),a=[n];function i(c,s){return e(),d("div",null,a)}const y=t(l,[["render",i],["__file","HTTP状态码-c5f6125a.html.vue"]]);export{y as default};
